 1	import type { FC } from 'react';
 2	import { DetailsItem } from 'src/components/DetailItems/DetailItem';
 3	import { PROVIDERS } from 'src/utils/enums';
 4	import { useForkliftTranslation } from 'src/utils/i18n';
 5	import { isProviderLocalOpenshift } from 'src/utils/resources';
 6	
 7	import { Label } from '@patternfly/react-core';
 8	
 9	import type { ProviderDetailsItemProps } from './ProviderDetailsItem';
10	
11	export const TypeDetailsItem: FC<ProviderDetailsItemProps> = ({
12	  helpContent,
13	  moreInfoLink,
14	  resource: provider,
15	}) => {
16	  const { t } = useForkliftTranslation();
17	
18	  const type = PROVIDERS[provider?.spec?.type] ?? provider?.spec?.type;
19	
20	  const defaultMoreInfoLink =
21	    'https://docs.redhat.com/en/documentation/migration_toolkit_for_virtualization/2.9/html/installing_and_using_the_migration_toolkit_for_virtualization/migrating-virt_cnv#adding-source-provider_cnv';
22	  const defaultHelpContent = t(
23	    `Specify the type of source provider. Allowed values are ova, ovirt, vsphere,
24	      openshift, and openstack. This label is needed to verify the credentials are correct when the remote system is accessible and, for RHV, to retrieve the Manager CA certificate when
25	      a third-party certificate is specified.`,
26	  );
27	
28	  return (
29	    <DetailsItem
30	      testId="type-detail-item"
31	      title={t('Type')}
32	      content={
33	        <>
34	          {type}{' '}
35	          {isProviderLocalOpenshift(provider) && (
36	            <Label isCompact color={'grey'} className="forklift-table__flex-cell-label">
37	              {t('Host cluster')}
38	            </Label>
39	          )}
40	          {provider?.spec?.type === 'vsphere' &&
41	            (provider?.spec?.settings?.sdkEndpoint === 'esxi' ? (
42	              <Label isCompact color={'grey'} className="forklift-table__flex-cell-label">
43	                {t('ESXi')}
44	              </Label>
45	            ) : (
46	              <Label isCompact color={'grey'} className="forklift-table__flex-cell-label">
47	                {t('vCenter')}
48	              </Label>
49	            ))}
50	        </>
51	      }
52	      moreInfoLink={moreInfoLink ?? defaultMoreInfoLink}
53	      helpContent={helpContent ?? defaultHelpContent}
54	      crumbs={['Provider', 'spec', 'type']}
55	    />
56	  );
57	};

